// Merge thresholds config and digest agent prompt from fetched data
const allItems = $input.all();

let thresholdsConfig = {};
let digestPrompt = null;

for (const item of allItems) {
  const data = item.json;
  // Thresholds config has runtime/ingestion/publishing sections
  if (data.runtime || data.ingestion || data.publishing) {
    thresholdsConfig = data;
  }
  // Digest prompt has content and name fields
  else if (data.content && (data.name === 'digest' || data.content.includes('digest'))) {
    digestPrompt = data;
  }
}

console.log(`Loaded thresholds config: runtime.use_stubs=${thresholdsConfig.runtime?.use_stubs}`);
console.log(`Loaded digest prompt: ${digestPrompt?.content?.length || 0} chars`);

return [{
  json: {
    ...thresholdsConfig,
    _agents: {
      digest: digestPrompt?.content || ''
    }
  }
}];

// Calculate date range for digest
// Uses config values from merged config + agents

const merged = $input.first().json;
const digestConfig = merged.digest || {};
const runtimeConfig = merged.runtime || { use_stubs: true };
const agents = merged._agents;

// Get thresholds from config
const minInsights = digestConfig.min_insights || 3;
const maxPerSection = digestConfig.max_per_section || 10;

const now = new Date();
const periodEnd = new Date(now);
periodEnd.setUTCDate(periodEnd.getUTCDate() - 1); // Yesterday
periodEnd.setUTCHours(23, 59, 59, 999);

const periodStart = new Date(periodEnd);
periodStart.setUTCDate(periodStart.getUTCDate() - 6); // 7 days ago
periodStart.setUTCHours(0, 0, 0, 0);

// Format dates for SQL query and display
const formatDateSQL = (d) => d.toISOString();
const formatDateDisplay = (d) => d.toISOString().split('T')[0];

console.log(`Using thresholds from config: minInsights=${minInsights}, maxPerSection=${maxPerSection}`);
console.log(`Runtime config: use_stubs=${runtimeConfig.use_stubs}`);
console.log(`Loaded digest agent prompt: ${agents?.digest?.length || 0} chars`);

return [{
  json: {
    periodStartSQL: formatDateSQL(periodStart),
    periodEndSQL: formatDateSQL(periodEnd),
    periodStartDisplay: formatDateDisplay(periodStart),
    periodEndDisplay: formatDateDisplay(periodEnd),
    digestId: `digest-${formatDateDisplay(periodEnd)}`,
    generatedAt: now.toISOString(),
    _thresholds: {
      runtime: runtimeConfig,
      minInsights,
      maxPerSection
    },
    _agents: agents
  }
}];

// Merge insights and project ideas with period data
const allItems = $input.all().map(item => item.json);
const periodData = $('Calculate Period').first().json;
const thresholds = periodData._thresholds || {};
const agents = periodData._agents;
const minInsights = thresholds.minInsights || 3;

// Separate insights from project ideas based on structure
// Insights have 'title' and 'topics', project ideas have 'problem_statement'
const insights = [];
const projectIdeas = [];

for (const item of allItems) {
  if (!item.id) continue;
  if (item.problem_statement) {
    // This is a project idea
    projectIdeas.push(item);
  } else if (item.title || item.tldr) {
    // This is an insight
    insights.push(item);
  }
}

console.log(`Found ${insights.length} insights and ${projectIdeas.length} project ideas for period`);

// Check if we have minimum required insights from config
if (!insights || insights.length < minInsights) {
  console.log(`Only ${insights.length} insights found, minimum required: ${minInsights}`);
  return [{
    json: {
      ...periodData,
      insights: insights,
      projectIdeas: projectIdeas,
      insightCount: insights.length,
      projectIdeaCount: projectIdeas.length,
      hasInsights: false,
      skipReason: `Insufficient insights (${insights.length}/${minInsights} required)`,
      _agents: agents
    }
  }];
}

return [{
  json: {
    ...periodData,
    insights: insights,
    projectIdeas: projectIdeas,
    insightCount: insights.length,
    projectIdeaCount: projectIdeas.length,
    hasInsights: true,
    _agents: agents
  }
}];

// Group insights by topic and prepare aggregated data
// Uses maxPerSection threshold from config
const data = $input.first().json;
const insights = data.insights || [];
const projectIdeas = data.projectIdeas || [];
const thresholds = data._thresholds || {};
const agents = data._agents;
const maxPerSection = thresholds.maxPerSection || 10;

// Group insights by primary topic (first topic in array)
const byTopic = {};
const topicCounts = {};

for (const insight of insights) {
  const topics = insight.topics || [];
  const primaryTopic = topics[0] || 'other';

  if (!byTopic[primaryTopic]) {
    byTopic[primaryTopic] = [];
    topicCounts[primaryTopic] = 0;
  }
  byTopic[primaryTopic].push(insight);
  topicCounts[primaryTopic]++;

  // Also count all topics for ranking
  for (const topic of topics) {
    if (topic !== primaryTopic) {
      topicCounts[topic] = (topicCounts[topic] || 0) + 1;
    }
  }
}

// Sort topics by count for top_topics
const topTopics = Object.entries(topicCounts)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 5)
  .map(([topic]) => topic);

// Collect all citations
const allCitations = [];
for (const insight of insights) {
  if (insight.citations) {
    allCitations.push(...insight.citations);
  }
}
const uniqueCitations = [...new Set(allCitations)];

// Build sections data for LLM - limit per section using maxPerSection from config
const sections = Object.entries(byTopic).map(([topic, topicInsights]) => ({
  topic,
  insightCount: topicInsights.length,
  insights: topicInsights.slice(0, maxPerSection).map(i => ({
    id: i.id,
    title: i.title,
    tldr: i.tldr,
    score: i.freedom_relevance_score,
    published_url: i.published_url,
    citations: i.citations
  }))
}));

// Format project ideas for LLM
const formattedProjectIdeas = projectIdeas.map(idea => ({
  id: idea.id,
  problem_statement: idea.problem_statement,
  proposed_solution: idea.proposed_solution,
  mvp_scope: idea.mvp_scope,
  feasibility_score: idea.feasibility_score,
  impact_score: idea.impact_score,
  status: idea.status,
  github_issue_url: idea.github_issue_url,
  affected_groups: idea.affected_groups
}));

console.log(`Aggregated insights into ${sections.length} sections (max ${maxPerSection} per section)`);
console.log(`Including ${formattedProjectIdeas.length} project ideas for digest`);

// Pass through runtime config for stub/real toggle
const runtime = data._thresholds?.runtime || { use_stubs: true };

return [{
  json: {
    ...data,
    byTopic,
    sections,
    topTopics,
    uniqueCitations,
    formattedProjectIdeas,
    topicSummary: Object.entries(topicCounts).map(([t, c]) => `${t}: ${c}`).join(', '),
    _usedThresholds: {
      maxPerSection
    },
    _runtime: runtime
  }
}];

// STUB: DigestComposer Agent
// Simulates Claude API response for digest generation
// Replace with real HTTP Request to Claude API when ready

const data = $input.first().json;
const insights = data.insights || [];
const sections = data.sections || [];
const topTopics = data.topTopics || [];
const projectIdeas = data.formattedProjectIdeas || [];

// Topic display names
const topicNames = {
  'bitcoin': 'Bitcoin & Payments',
  'zk': 'Zero Knowledge',
  'censorship-resistance': 'Censorship Resistance',
  'comms': 'Secure Communications',
  'payments': 'Payments & Finance',
  'identity': 'Identity & Privacy',
  'privacy': 'Privacy',
  'surveillance': 'Surveillance',
  'activism': 'Activism',
  'sovereignty': 'Sovereignty'
};

// Generate executive TL;DR
const topInsights = insights.slice(0, 3);
let executiveTldr = `This week brought ${data.insightCount} signals across ${topTopics.length} key areas of freedom technology. `;

if (topInsights.length > 0) {
  executiveTldr += `Top stories include: ${topInsights.map(i => i.title).join('; ')}. `;
}

if (projectIdeas.length > 0) {
  executiveTldr += `${projectIdeas.length} new project idea${projectIdeas.length > 1 ? 's were' : ' was'} generated. `;
}

if (topTopics.length > 0) {
  executiveTldr += `Most active topics: ${topTopics.slice(0, 3).map(t => topicNames[t] || t).join(', ')}.`;
}

// Generate sections markdown
const sectionMarkdowns = [];

for (const section of sections) {
  const topicTitle = topicNames[section.topic] || section.topic;
  let md = `### ${topicTitle}\n\n`;

  for (const insight of section.insights) {
    const url = insight.published_url || '#';
    md += `- [${insight.title}](${url}) \u2014 ${insight.tldr}\n`;
  }

  sectionMarkdowns.push({
    title: topicTitle,
    content_markdown: md,
    insight_ids: section.insights.map(i => i.id)
  });
}

// Identify emerging patterns (stub - simple keyword analysis)
const emergingPatterns = [];
if (data.insightCount >= 3) {
  emergingPatterns.push({
    pattern: `Increased activity in ${topTopics[0] || 'freedom tech'} space`,
    supporting_signals: insights.slice(0, 2).map(i => i.id)
  });
}
if (insights.some(i => (i.geo || []).length > 0)) {
  const geos = [...new Set(insights.flatMap(i => i.geo || []))];
  if (geos.length > 0) {
    emergingPatterns.push({
      pattern: `Geographic focus on ${geos.slice(0, 3).join(', ')}`,
      supporting_signals: insights.filter(i => (i.geo || []).length > 0).slice(0, 2).map(i => i.id)
    });
  }
}

// Format project ideas for output
const formattedIdeasOutput = projectIdeas.map(idea => ({
  id: idea.id,
  problem_statement: idea.problem_statement,
  proposed_solution: idea.proposed_solution,
  impact_score: idea.impact_score,
  feasibility_score: idea.feasibility_score,
  github_issue_url: idea.github_issue_url,
  status: idea.status
}));

// Looking ahead suggestions
const lookingAhead = [
  'Continue monitoring developments in ' + (topTopics[0] ? (topicNames[topTopics[0]] || topTopics[0]) : 'key freedom tech areas'),
  'Watch for regulatory responses to emerging tools',
  'Track adoption metrics for highlighted projects'
];

if (projectIdeas.length > 0) {
  lookingAhead.push(`Review and triage ${projectIdeas.length} new project idea${projectIdeas.length > 1 ? 's' : ''} for potential implementation`);
}

// Build full digest content
const digestOutput = {
  executive_tldr: executiveTldr,
  sections: sectionMarkdowns,
  emerging_patterns: emergingPatterns,
  project_ideas: formattedIdeasOutput,
  looking_ahead: lookingAhead,
  insight_count: data.insightCount,
  project_idea_count: projectIdeas.length,
  top_topics: topTopics
};

// Format as Claude API response structure
return [{
  json: {
    content: [{
      type: 'text',
      text: JSON.stringify(digestOutput)
    }],
    _periodData: {
      periodStartDisplay: data.periodStartDisplay,
      periodEndDisplay: data.periodEndDisplay,
      digestId: data.digestId
    },
    _uniqueCitations: data.uniqueCitations,
    _projectIdeas: projectIdeas,
    _agents: data._agents
  }
}];

