// Process real Claude API response and add pass-through data for digest
const claudeResponse = $input.first().json;
const aggregateData = $('Aggregate by Topic').first().json;

// Return in same format as stub for Parse Digest Output compatibility
return [{
  json: {
    content: claudeResponse.content,
    _periodData: {
      periodStartDisplay: aggregateData.periodStartDisplay,
      periodEndDisplay: aggregateData.periodEndDisplay,
      digestId: aggregateData.digestId
    },
    _uniqueCitations: aggregateData.uniqueCitations,
    _projectIdeas: aggregateData.formattedProjectIdeas || [],
    _agents: aggregateData._agents
  }
}];

// Parse digest output from Claude API format
const input = $input.first().json;
let digest;

try {
  let text = input.content[0].text;

  // Strip markdown code blocks if present (Claude often wraps JSON in ```json...```)
  text = text.trim();
  if (text.startsWith('```')) {
    // Remove opening fence (```json or ```)
    text = text.replace(/^```(?:json)?\s*\n?/, '');
    // Remove closing fence
    text = text.replace(/\n?```\s*$/, '');
  }

  digest = JSON.parse(text.trim());
} catch (e) {
  // Fallback if parsing fails
  console.log('Parse Digest error:', e.message);
  console.log('Raw text:', input.content?.[0]?.text?.substring(0, 200));
  digest = {
    executive_tldr: 'Failed to generate digest summary: ' + e.message,
    sections: [],
    emerging_patterns: [],
    project_ideas: [],
    looking_ahead: ['Review source insights manually'],
    insight_count: 0,
    project_idea_count: 0,
    top_topics: []
  };
}

const periodData = input._periodData;
const uniqueCitations = input._uniqueCitations || [];
const projectIdeas = input._projectIdeas || digest.project_ideas || [];
const projectIdeaCount = projectIdeas.length || digest.project_idea_count || 0;

// Build full markdown content for digest
let contentMarkdown = `---\nid: "${periodData.digestId}"\ntype: "weekly-digest"\npublished_at: "${new Date().toISOString()}"\nperiod_start: "${periodData.periodStartDisplay}"\nperiod_end: "${periodData.periodEndDisplay}"\ninsight_count: ${digest.insight_count}\nproject_idea_count: ${projectIdeaCount}\n---\n\n`;

contentMarkdown += `# Weekly Freedom Tech Digest\n\n`;
contentMarkdown += `*${periodData.periodStartDisplay} to ${periodData.periodEndDisplay}*\n\n`;

contentMarkdown += `## TL;DR\n\n${digest.executive_tldr}\n\n`;

contentMarkdown += `## Top Signals\n\n`;
for (const section of (digest.sections || [])) {
  contentMarkdown += section.content_markdown + '\n';
}

if (digest.emerging_patterns && digest.emerging_patterns.length > 0) {
  contentMarkdown += `## Emerging Patterns\n\n`;
  for (const pattern of digest.emerging_patterns) {
    contentMarkdown += `- **${pattern.pattern}**\n`;
  }
  contentMarkdown += '\n';
}

// Add Project Ideas Generated This Week section
if (projectIdeas && projectIdeas.length > 0) {
  contentMarkdown += `## Project Ideas Generated This Week\n\n`;
  contentMarkdown += `This week's high-signal insights inspired ${projectIdeas.length} new project idea${projectIdeas.length > 1 ? 's' : ''}:\n\n`;

  for (const idea of projectIdeas) {
    const statusBadge = idea.status === 'build_candidate' ? ' \u2b50' : '';
    const issueLink = idea.github_issue_url ? ` ([GitHub Issue](${idea.github_issue_url}))` : '';

    contentMarkdown += `### ${idea.problem_statement?.substring(0, 100)}...${statusBadge}\n\n`;
    contentMarkdown += `**Proposed Solution**: ${idea.proposed_solution?.substring(0, 200)}...\n\n`;
    contentMarkdown += `**Impact Score**: ${idea.impact_score}/100 | **Feasibility Score**: ${idea.feasibility_score}/100${issueLink}\n\n`;

    if (idea.affected_groups && idea.affected_groups.length > 0) {
      contentMarkdown += `**Affected Groups**: ${idea.affected_groups.join(', ')}\n\n`;
    }
  }
}

if (digest.looking_ahead && digest.looking_ahead.length > 0) {
  contentMarkdown += `## Looking Ahead\n\n`;
  for (const item of digest.looking_ahead) {
    contentMarkdown += `- ${item}\n`;
  }
  contentMarkdown += '\n';
}

if (uniqueCitations && uniqueCitations.length > 0) {
  contentMarkdown += `## Sources This Week\n\n`;
  for (const citation of uniqueCitations.slice(0, 20)) {
    contentMarkdown += `- ${citation}\n`;
  }
}

// Prepare data for database insert
return [{
  json: {
    periodStart: periodData.periodStartDisplay,
    periodEnd: periodData.periodEndDisplay,
    insightCount: digest.insight_count,
    projectIdeaCount: projectIdeaCount,
    executiveTldr: digest.executive_tldr,
    contentMarkdown: contentMarkdown,
    topTopics: digest.top_topics || [],
    digestId: periodData.digestId
  }
}];

// Build INSERT query for digests table with proper escaping
const data = $input.first().json;

function escapeStr(str) {
  if (str === null || str === undefined) return 'NULL';
  return "'" + String(str).replace(/'/g, "''") + "'";
}

function formatPgArray(arr) {
  if (!arr || arr.length === 0) return "'{}'";
  const escaped = arr.map(s => '"' + String(s).replace(/"/g, '\\"').replace(/'/g, "''") + '"');
  return "'{" + escaped.join(',') + "}'";
}

const publishedAt = new Date().toISOString();
const publishedUrl = `https://libertas.fgu.tech/digests/${data.digestId}`;

const query = `INSERT INTO digests (
  period_start, period_end, insight_count, executive_tldr,
  content_markdown, top_topics, published_url, published_at
) VALUES (
  ${escapeStr(data.periodStart)}::date,
  ${escapeStr(data.periodEnd)}::date,
  ${data.insightCount},
  ${escapeStr(data.executiveTldr)},
  ${escapeStr(data.contentMarkdown)},
  ${formatPgArray(data.topTopics)},
  ${escapeStr(publishedUrl)},
  ${escapeStr(publishedAt)}::timestamptz
) ON CONFLICT (period_start, period_end) 
DO UPDATE SET
  insight_count = EXCLUDED.insight_count,
  executive_tldr = EXCLUDED.executive_tldr,
  content_markdown = EXCLUDED.content_markdown,
  top_topics = EXCLUDED.top_topics,
  published_url = EXCLUDED.published_url,
  published_at = EXCLUDED.published_at,
  updated_at = NOW()
RETURNING id, period_start, period_end, published_url`;

return [{ 
  json: { 
    query, 
    digestData: {
      ...data,
      publishedUrl,
      publishedAt
    }
  } 
}];

// Merge insert result with digest data, generate feeds, and pass through runtime config
const insertResult = $input.first().json;
const digestData = $('Build Digest Query').first().json.digestData;
const periodData = $('Calculate Period').first().json;
const runtime = periodData._thresholds?.runtime || { use_stubs: true };

const digestId = insertResult.id;

// Extract just the date portion (YYYY-MM-DD) from ISO timestamps or date strings
// Database returns ISO timestamps like "2026-01-13T00:00:00.000Z"
function formatDate(dateVal) {
  if (!dateVal) return '';
  const str = String(dateVal);
  // If it's already YYYY-MM-DD format, return as-is
  if (/^\d{4}-\d{2}-\d{2}$/.test(str)) return str;
  // Extract date from ISO timestamp
  return str.split('T')[0];
}

const periodStart = formatDate(insertResult.period_start || digestData.periodStart);
const periodEnd = formatDate(insertResult.period_end || digestData.periodEnd);
const publishedUrl = insertResult.published_url || digestData.publishedUrl;

// Site metadata
const siteUrl = 'https://libertas.fgu.tech';
const buildDate = new Date().toUTCString();

// Helper to escape XML
function escapeXml(str) {
  if (!str) return '';
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/\"/g, '&quot;')
    .replace(/'/g, '&apos;');
}

// Generate digest slug
const digestSlug = `weekly-${periodEnd}`;
const digestLink = `${siteUrl}/digests/${digestSlug}`;

// Generate RSS feed for digests
const rssItem = `  <item>\n    <title>Weekly Digest: ${escapeXml(periodStart)} to ${escapeXml(periodEnd)}</title>\n    <link>${digestLink}</link>\n    <guid isPermaLink=\"true\">${digestLink}</guid>\n    <pubDate>${buildDate}</pubDate>\n    <description>${escapeXml(digestData.executiveTldr)}</description>\n    <category>weekly-digest</category>\n  </item>`;

const digestsRssFeed = `<?xml version=\"1.0\" encoding=\"UTF-8\"?>\n<rss version=\"2.0\" xmlns:atom=\"http://www.w3.org/2005/Atom\">\n<channel>\n  <title>Libertas - Weekly Digests</title>\n  <link>${siteUrl}</link>\n  <description>Weekly summaries of freedom technology developments</description>\n  <language>en-us</language>\n  <lastBuildDate>${buildDate}</lastBuildDate>\n  <atom:link href=\"${siteUrl}/digests-rss.xml\" rel=\"self\" type=\"application/rss+xml\"/>\n  <generator>Libertas n8n Workflow</generator>\n${rssItem}\n</channel>\n</rss>`;

// Generate JSON Feed for digests
const digestsJsonFeed = JSON.stringify({
  version: 'https://jsonfeed.org/version/1.1',
  title: 'Libertas - Weekly Digests',
  home_page_url: siteUrl,
  feed_url: `${siteUrl}/digests-feed.json`,
  description: 'Weekly summaries of freedom technology developments',
  language: 'en-US',
  items: [{
    id: digestId,
    url: digestLink,
    title: `Weekly Digest: ${periodStart} to ${periodEnd}`,
    summary: digestData.executiveTldr,
    content_text: digestData.executiveTldr,
    date_published: new Date().toISOString(),
    tags: ['weekly-digest'],
    _libertas: {
      insight_count: digestData.insightCount,
      period_start: periodStart,
      period_end: periodEnd
    }
  }]
}, null, 2);

console.log(`Generated digest feeds for ${periodStart} to ${periodEnd}`);

return [{
  json: {
    digestId,
    periodStart,
    periodEnd,
    publishedUrl,
    contentMarkdown: digestData.contentMarkdown,
    insightCount: digestData.insightCount,
    executiveTldr: digestData.executiveTldr,
    digestsRssFeed,
    digestsJsonFeed,
    _runtime: runtime
  }
}];

// STUB: GitHub commit for digest markdown and feeds
// Creates the markdown file content and simulates GitHub API response
// Updated to use website/public/content/digests/ path

const data = $input.first().json;

// Prepare file paths and content for GitHub
// Using website/public/content/digests/ for Next.js static serving
