const commitMessage = `Add weekly digest for ${data.periodStart} to ${data.periodEnd} and update feeds\n\nCo-authored-by: Claude <noreply@anthropic.com>`;

console.log(`[STUB] Would commit to GitHub (single atomic commit):`);
console.log(`  - ${digestPath} (${data.contentMarkdown.length} bytes)`);
console.log(`  - website/public/digests-rss.xml (${data.digestsRssFeed.length} bytes)`);
console.log(`  - website/public/digests-feed.json (${data.digestsJsonFeed.length} bytes)`);
console.log(`  - Co-authored by Claude`);

// Simulate successful GitHub commit response
return [{
  json: {
    success: true,
    stub: true,
    commit: {
      sha: 'stub-sha-' + Date.now(),
      message: commitMessage
    },
    files: [
      { path: digestPath, action: 'upsert' },
