    _digestPath: digestPath
  }
}];

// Prepare files for atomic GitHub commit via Git Data API
// Updated paths: digest goes to website/public/content/digests/, feeds to website/public/
const data = $input.first().json;

// Digest file path
const digestPath = `website/public/content/digests/weekly-${data.periodEnd}.md`;

return [{
  json: {
    ...data,
    _github: {
      owner: 'FGUTech',
      repo: 'libertas',
      branch: 'main',
      commitMessage: `Add weekly digest for ${data.periodStart} to ${data.periodEnd} and update feeds\n\nCo-authored-by: Claude <noreply@anthropic.com>`,
      files: [
        {
          path: digestPath,
          content: data.contentMarkdown
        },
        {
          path: 'website/public/digests-rss.xml',
          content: data.digestsRssFeed
        },
        {
          path: 'website/public/digests-feed.json',
          content: data.digestsJsonFeed
        }
      ]
    },
    _digestPath: digestPath
  }
}];

// Build tree entries for all files
const commitData = $('Prepare GitHub Commit').first().json;
const baseTreeSha = $input.first().json.tree.sha;
const parentCommitSha = $('Get Branch Ref').first().json.object.sha;

const treeEntries = commitData._github.files.map(file => ({
  path: file.path,
  mode: '100644',
